module traffic_light
(
    input rst_n,
    input clk,
    input pass_request,
    output reg [7:0] clock,
    output reg red
);

parameter IDLE = 2'b00;
parameter RED = 2'b01;
parameter YELLOW = 2'b10;
parameter GREEN = 2'b11;

reg [1:0] state, next_state;
reg [7:0] counter, next_counter;
reg [3:0] red_duration, yellow_duration, green_duration;
reg [3:0] next_red_duration, next_yellow_duration, next_green_duration;

always @(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
        state <= IDLE;
        counter <= 8'd10;
        red_duration <= 4'd60;
        yellow_duration <= 4'd5;
        green_duration <= 4'd10;
    end
    else begin
        state <= next_state;
        counter <= next_counter;
        red_duration <= next_red_duration;
        yellow_duration <= next_yellow_duration;
        green_duration <= next_green_duration;
    end
end

always @(*) begin
    case(state)
        IDLE: begin
            next_state = RED;
            next_counter = 8'd10;
            next_red_duration = 4'd60;
            next_yellow_duration = 4'd0;
            next_green_duration = 4'd0;
        end
        RED: begin
            if(counter == 8'd0) begin
                next_state = GREEN;
                next_counter = 8'd10;
            end
            else begin
                next_state = RED;
                next_counter = counter - 8'd1;
            end
            next_red_duration = red_duration;
            next_yellow_duration = 4'd0;
            next_green_duration = 4'd0;
        end
        YELLOW: begin
            if(counter == 8'd0) begin
                next_state = RED;
                next_counter = 8'd10;
            end
            else begin
                next_state = YELLOW;
                next_counter = counter - 8'd1;
            end
            next_red_duration = 4'd0;
            next_yellow_duration = 4'd5;
            next_green_duration = 4'd0;
        end
        GREEN: begin
            if(counter == 8'd0) begin
                next_state = YELLOW;
                next_counter = 8'd5;
            end
            else begin
                next_state = GREEN;
                next_counter = counter - 8'd1;
            end
            next_red_duration = 4'd0;
            next_yellow_duration = 4'd0;
            next_green_duration = green_duration;
        end
        default: begin
            next_state = IDLE;
            next_counter = 8'd10;
            next_red_duration = 4'd60;
            next_yellow_duration = 4'd5;
            next_green_duration = 4'd10;
        end
    endcase
end

always @(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
        red <= 1'b0;
        yellow <= 1'b0;
        green <= 1'b0;
        clock <= 8'd10;
    end
    else begin
        red <= (state == RED) ? 1'b1 : 1'b0;
        yellow <= (state == YELLOW) ? 1'b1 : 1'b0;
        green <= (state == GREEN) ? 1'b1 : 1'b0;
        clock <= counter;
    end
end

endmodule
